import { OpenAIEmbeddings } from "@langchain/openai";
import { OllamaEmbeddings } from "@langchain/ollama";
import { MemoryVectorStore } from "langchain/vectorstores/memory";

// Swap models without changing downstream code
const embeddings = new OpenAIEmbeddings({ model: "text-embedding-3-small" });
// const embeddings = new OllamaEmbeddings({ model: "nomic-embed-text" });

const store = await MemoryVectorStore.fromTexts(
  ["LangChain supports pgvector", "Redis can cache embeddings", "FAISS runs locally"],
  [{ id: 1 }, { id: 2 }, { id: 3 }],
  embeddings
);

const results = await store.similaritySearchWithScore("vector database options", 2);
console.log(results); // [ [Document, 0.91], [Document, 0.87] ]
